// Parse RSS/Atom feeds into normalized items
// Grab data from each named feed node directly

const rawFeeds = [];

try {
  const hn = $('Fetch Hacker News RSS').all();
  for (const item of hn) {
    const str = typeof item.json === 'string' ? item.json : (item.json.data || JSON.stringify(item.json));
    rawFeeds.push({ name: 'hackernews', weight: 1.5, xml: str });
  }
} catch(e) {}

try {
  const ph = $('Fetch Product Hunt RSS').all();
  for (const item of ph) {
    const str = typeof item.json === 'string' ? item.json : (item.json.data || JSON.stringify(item.json));
    rawFeeds.push({ name: 'producthunt', weight: 1.3, xml: str });
  }
} catch(e) {}

function extractItems(xml, sourceName, weight) {
  const items = [];
  if (!xml || xml.length < 50) return items;

  const itemRegex = /<(?:item|entry)[^>]*>([\s\S]*?)<\/(?:item|entry)>/gi;
  let match;

  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[1];

    const getTag = (tag) => {
      const r = new RegExp(
        '<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/' + tag + '>|' +
        '<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>',
        'i'
      );
      const m = block.match(r);
      return m ? (m[1] || m[2] || '').trim() : '';
    };

    let link = getTag('link');
    if (!link) {
      const hrefMatch = block.match(/href="([^"]+)"/i);
      if (hrefMatch) link = hrefMatch[1];
    }

    const title = getTag('title').replace(/<[^>]+>/g, '').trim();
    const desc = getTag('description').replace(/<[^>]+>/g, '').substring(0, 300);
    const content = getTag('content').replace(/<[^>]+>/g, '').substring(0, 300) || desc;
    const pubDate = getTag('pubDate') || getTag('published') || getTag('updated') || '';

    if (!title) continue;

    items.push({
      source: sourceName,
      source_weight: weight,
      title: title,
      url: link,
      description: (content || desc).substring(0, 200),
      published: pubDate,
      raw_text: (title + ' ' + desc + ' ' + content).toLowerCase()
    });
  }

  return items;
}

let allItems = [];

for (const feed of rawFeeds) {
  try {
    const items = extractItems(feed.xml, feed.name, feed.weight);
    allItems = allItems.concat(items);
  } catch(e) {}
}

if (allItems.length === 0) {
  return [{ json: { items: [], total_fetched: 0, feeds_processed: rawFeeds.length, error: 'No items parsed from any feed.' } }];
}

return [{ json: { items: allItems, total_fetched: allItems.length, feeds_processed: rawFeeds.length } }];

const data = $input.first().json;
const items = data.items;

if (!items || items.length === 0) {
  return [{ json: { scored_items: [], total_signals: 0, total_fetched: 0, error: 'No items to score' } }];
}

// ============================================
// CUSTOMIZE YOUR KEYWORD GROUPS BELOW
// Add, remove, or adjust keywords and weights
// to match your industry and interests
// ============================================
const keywordGroups = {
  'ai_automation': {
    keywords: ['ai agent', 'ai automation', 'llm', 'gpt', 'claude', 'copilot', 'ai tool', 'artificial intelligence', 'machine learning', 'generative ai', 'ai-powered', 'langchain', 'rag'],
    weight: 2.0,
    category: 'AI & Automation'
  },
  'no_code': {
    keywords: ['no-code', 'nocode', 'low-code', 'lowcode', 'n8n', 'zapier', 'make.com', 'automation platform', 'workflow automation', 'airtable'],
    weight: 1.8,
    category: 'No-Code / Low-Code'
  },
  'saas_business': {
    keywords: ['saas', 'mrr', 'arr', 'churn', 'b2b saas', 'micro-saas', 'bootstrapped', 'indie hacker', 'recurring revenue', 'subscription'],
    weight: 1.5,
    category: 'SaaS & Business'
  },
  'developer_tools': {
    keywords: ['developer tool', 'dev tool', 'api', 'sdk', 'open source', 'cli tool', 'developer experience', 'dx', 'devops', 'infrastructure'],
    weight: 1.3,
    category: 'Developer Tools'
  },
  'marketing_growth': {
    keywords: ['seo', 'content marketing', 'growth hack', 'conversion', 'landing page', 'email marketing', 'organic traffic', 'product-led', 'plg', 'go-to-market'],
    weight: 1.4,
    category: 'Marketing & Growth'
  },
  'pricing_monetization': {
    keywords: ['pricing', 'monetization', 'freemium', 'paywall', 'revenue model', 'billing', 'payment', 'stripe', 'pricing strategy'],
    weight: 1.6,
    category: 'Pricing & Monetization'
  },
  'remote_productivity': {
    keywords: ['remote work', 'async', 'productivity', 'collaboration tool', 'project management', 'notion', 'obsidian', 'second brain', 'knowledge management'],
    weight: 1.1,
    category: 'Remote & Productivity'
  }
};

const scoredItems = [];

for (const item of items) {
  const text = item.raw_text || '';
  let totalScore = 0;
  const matchedGroups = [];
  const matchedKeywords = [];

  for (const [groupId, group] of Object.entries(keywordGroups)) {
    let groupHits = 0;

    for (const kw of group.keywords) {
      if (text.includes(kw)) {
        groupHits++;
        matchedKeywords.push(kw);
      }
    }

    if (groupHits > 0) {
      const groupScore = groupHits * group.weight;
      totalScore += groupScore;
      matchedGroups.push({
        group: group.category,
        hits: groupHits,
        score: parseFloat(groupScore.toFixed(2))
      });
    }
  }

  totalScore = totalScore * (item.source_weight || 1);

  const titleText = (item.title || '').toLowerCase();
  let titleBonus = 0;
  for (const [groupId, group] of Object.entries(keywordGroups)) {
    for (const kw of group.keywords) {
      if (titleText.includes(kw)) {
        titleBonus += 1.5;
      }
    }
  }
  totalScore += titleBonus;

  if (totalScore > 0) {
    scoredItems.push({
      title: item.title,
      url: item.url,
      source: item.source,
      description: item.description,
      published: item.published,
      signal_score: parseFloat(totalScore.toFixed(2)),
      matched_groups: matchedGroups,
      matched_keywords: [...new Set(matchedKeywords)],
      primary_category: matchedGroups.length > 0 
        ? matchedGroups.sort((a, b) => b.score - a.score)[0].group 
        : 'General',
      title_match: titleBonus > 0
    });
  }
}

scoredItems.sort((a, b) => b.signal_score - a.signal_score);

return [{ json: { scored_items: scoredItems, total_signals: scoredItems.length, total_fetched: items.length } }];

const data = $input.first().json;
const items = data.scored_items || [];

if (items.length === 0) {
  const today = new Date().toISOString().split('T')[0];
  return [{
    json: {
      date: today,
      themes: [],
      total_signals: 0,
      total_fetched: data.total_fetched || 0,
      top_items: [],
      note: 'No keyword matches found today.'
    }
  }];
}

const themes = {};

for (const item of items) {
  const cat = item.primary_category;
  if (!themes[cat]) {
    themes[cat] = {
      category: cat,
      items: [],
      total_score: 0,
      source_diversity: new Set(),
      all_keywords: []
    };
  }
  themes[cat].items.push(item);
  themes[cat].total_score += item.signal_score;
  themes[cat].source_diversity.add(item.source);
  themes[cat].all_keywords.push(...(item.matched_keywords || []));
}

const themeResults = [];

for (const [cat, theme] of Object.entries(themes)) {
  const itemCount = theme.items.length;
  const sourceDiversity = theme.source_diversity.size;
  const avgScore = theme.total_score / itemCount;

  const diversityBonus = 1 + (sourceDiversity - 1) * 0.3;
  const volumeBonus = 1 + Math.log2(Math.max(itemCount, 1)) * 0.2;
  const themeStrength = parseFloat((theme.total_score * diversityBonus * volumeBonus).toFixed(2));

  let signalLevel;
  if (themeStrength >= 30) signalLevel = 'VERY_STRONG';
  else if (themeStrength >= 15) signalLevel = 'STRONG';
  else if (themeStrength >= 8) signalLevel = 'MODERATE';
  else signalLevel = 'WEAK';

  const kwFreq = {};
  for (const kw of theme.all_keywords) {
    kwFreq[kw] = (kwFreq[kw] || 0) + 1;
  }
  const topKeywords = Object.entries(kwFreq)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([kw, count]) => kw + ' (' + count + ')');

  themeResults.push({
    category: cat,
    signal_level: signalLevel,
    theme_strength: themeStrength,
    item_count: itemCount,
    sources: [...theme.source_diversity],
    source_count: sourceDiversity,
    avg_item_score: parseFloat(avgScore.toFixed(2)),
    top_keywords: topKeywords,
    top_items: theme.items
      .sort((a, b) => b.signal_score - a.signal_score)
      .slice(0, 5)
      .map(i => ({
        title: i.title,
        source: i.source,
        score: i.signal_score,
        url: i.url
      }))
  });
}

themeResults.sort((a, b) => b.theme_strength - a.theme_strength);

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    date: today,
    themes: themeResults,
    total_signals: data.total_signals,
    total_fetched: data.total_fetched,
    top_items: items.slice(0, 15).map(i => ({
      title: i.title,
      source: i.source,
      score: i.signal_score,
      category: i.primary_category,
      url: i.url
    }))
  }
}];

const data = $input.first().json;
const themes = data.themes || [];
const topItems = data.top_items || [];
const today = data.date || new Date().toISOString().split('T')[0];

if (themes.length === 0 && topItems.length === 0) {
  const report = 'SIGNAL INTELLIGENCE REPORT — ' + today + '\n\nSources scanned: ' + (data.total_fetched || 0) + ' items\nNo matching signals found today.\n\nTip: Broaden keywords in the Score node, or add more RSS sources.';
  return [{
    json: {
      report: report,
      report_html: '<h2>Signal Report — ' + today + '</h2><p>No matching signals found today.</p>',
      date: today,
      themes: [],
      top_items: [],
      strong_theme_count: 0,
      total_signals: 0
    }
  }];
}

let report = 'SIGNAL INTELLIGENCE REPORT — ' + today + '\n';
report += 'Sources scanned: ' + data.total_fetched + ' items → ' + data.total_signals + ' signals detected\n';
report += '━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
report += 'THEME STRENGTH RANKING:\n\n';

for (const theme of themes) {
  report += theme.signal_level + '  ' + theme.category + '\n';
  report += '   Strength: ' + theme.theme_strength + ' | Items: ' + theme.item_count + ' | Sources: ' + theme.sources.join(', ') + '\n';
  report += '   Keywords: ' + theme.top_keywords.join(', ') + '\n\n';
}

report += '━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
report += 'TOP 10 STRONGEST SIGNALS:\n\n';

for (let i = 0; i < Math.min(topItems.length, 10); i++) {
  const item = topItems[i];
  report += (i + 1) + '. ' + item.title + '\n';
  report += '   Score: ' + item.score + ' | Source: ' + item.source + ' | Theme: ' + item.category + '\n';
  if (item.url) report += '   ' + item.url + '\n';
  report += '\n';
}

const strongThemes = themes.filter(t => t.theme_strength >= 15);
if (strongThemes.length > 0) {
  report += '━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
  report += 'ACTION ITEMS — Strong signals detected:\n\n';
  for (const t of strongThemes) {
    report += '• ' + t.category + ' is surging across ' + t.source_count + ' sources. ';
    report += 'Top keyword: ' + (t.top_keywords[0] || 'n/a') + '. ';
    report += 'Consider creating content or building in this space.\n';
  }
}

let html = '<h2>Signal Intelligence Report — ' + today + '</h2>';
html += '<p>Sources scanned: ' + data.total_fetched + ' items → <strong>' + data.total_signals + ' signals</strong></p><hr/>';
html += '<h3>Theme Strength</h3><table style="border-collapse:collapse;width:100%;">';
html += '<tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;border:1px solid #ddd;">Theme</th><th style="padding:8px;border:1px solid #ddd;">Signal</th><th style="padding:8px;border:1px solid #ddd;">Strength</th><th style="padding:8px;border:1px solid #ddd;">Items</th><th style="padding:8px;border:1px solid #ddd;">Sources</th></tr>';
for (const theme of themes) {
  html += '<tr><td style="padding:8px;border:1px solid #ddd;">' + theme.category + '</td>';
  html += '<td style="padding:8px;border:1px solid #ddd;">' + theme.signal_level + '</td>';
  html += '<td style="padding:8px;border:1px solid #ddd;">' + theme.theme_strength + '</td>';
  html += '<td style="padding:8px;border:1px solid #ddd;">' + theme.item_count + '</td>';
  html += '<td style="padding:8px;border:1px solid #ddd;">' + theme.sources.join(', ') + '</td></tr>';
}
html += '</table>';
html += '<h3>Top Signals</h3><ol>';
for (let i = 0; i < Math.min(topItems.length, 10); i++) {
  const item = topItems[i];
  html += '<li><strong>' + item.title + '</strong><br/>Score: ' + item.score + ' | ' + item.source + ' | ' + item.category;
  if (item.url) html += ' | <a href="' + item.url + '">Link</a>';
  html += '</li>';
}
html += '</ol>';

return [{
  json: {
    report: report,
    report_html: html,
    date: today,
    themes: themes,
    top_items: topItems,
    strong_theme_count: strongThemes.length,
    total_signals: data.total_signals
  }
}];

const data = $input.first().json;
const items = data.top_items || [];

if (items.length === 0) {
  return [{ json: { date: data.date, title: 'No signals detected', source: '-', score: 0, category: '-', url: '-' } }];
}

return items.map(item => ({
  json: {
    date: data.date,
    title: item.title || '',
    source: item.source || '',
    score: item.score || 0,
    category: item.category || '',
    url: item.url || ''
  }
}));

const data = $input.first().json;
const themes = data.themes || [];

if (themes.length === 0) {
  return [{ json: { date: data.date, category: 'No themes', signal_level: '-', theme_strength: 0, item_count: 0, sources: '-', top_keywords: '-' } }];
}

return themes.map(theme => ({
  json: {
    date: data.date,
    category: theme.category,
    signal_level: theme.signal_level,
    theme_strength: theme.theme_strength,
    item_count: theme.item_count,
    sources: theme.sources.join(', '),
    top_keywords: theme.top_keywords.join(', ')
  }
}));
